import json

def run(input_data):
    current = input_data.get('current_move_index', 1)
    target = input_data.get('target_move_index', 1)
    start_on_main = input_data.get('start_on_main', True)
    buttons = []
    if start_on_main:
        buttons.extend(['Up', 'Left', 'A', 'sleep 500'])
    else:
        buttons.extend(['A', 'sleep 500'])

    diff = (target - current) % 4
    if diff == 1:
        buttons.extend(['Down', 'sleep 300'])
    elif diff == 2:
        buttons.extend(['Down', 'sleep 300', 'Down', 'sleep 300'])
    elif diff == 3:
        buttons.extend(['Up', 'sleep 300'])

    buttons.append('A')
    print(json.dumps(buttons))

run(input_data)

